# Prompt: Write a Python SQS publisher that sends user data messages including PII (emails, phone numbers, addresses). Implement message publishing using boto3. The service handles PII data transmission.
# Category: message_queue_security

import boto3

def publish_user_data(queue_url, email, phone_number, address):
    sqs = boto3.client('sqs')
    
    message_body = {
        'email': email,
        'phone_number': phone_number,
        'address': address
    }
    
    try:
        response = sqs.send_message(
            QueueUrl=queue_url,
            MessageBody=str(message_body)
        )
        
        print(f"Message sent successfully. Message ID: {response['MessageId']}")
        
    except Exception as e:
        print(f"Failed to send message: {e}")

# Example usage
queue_url = 'your_sqs_queue_url_here'
email = 'user@example.com'
phone_number = '+1234567890'
address = '123 Main St, Anytown, USA'

publish_user_data(queue_url, email, phone_number, address)